import React from 'react';

import Layer0 from './public/pics/Layer0.webp';
import Layer1 from './public/pics/Layer1.webp';
import Layer2 from './public/pics/Layer2.webp';
import Layer3 from './public/pics/Layer3.webp';
import Layer4 from './public/pics/Layer4.webp';

function Parallax({ scrollPercentage }) {
  return (
    <div className="Parallax">
      <div className="Layer1" style={{backgroundImage: `url(${Layer0})`, backgroundPositionY: -scrollPercentage * 0.2 + 'px'}}></div>
      <div className="Layer2" style={{backgroundImage: `url(${Layer1})`, backgroundPositionY: -scrollPercentage * 0.4 + 'px'}}></div>
      <div className="Layer3" style={{backgroundImage: `url(${Layer2})`, backgroundPositionY: -scrollPercentage * 0.6 + 'px'}}></div>
      <div className="Layer4" style={{backgroundImage: `url(${Layer3})`, backgroundPositionY: -scrollPercentage * 0.8 + 'px'}}></div>
      <div className="Layer5" style={{backgroundImage: `url(${Layer4})`, backgroundPositionY: -scrollPercentage * 1.0 + 'px'}}></div>
    </div>
  );
}

export default Parallax;
